import { revalidateTag } from 'next/cache';
import { getAllProducts } from '@/lib/db';

export default async function Page() {
  const products = await getAllProducts();

  async function syncCatalog() {
    'use server';

    // Keep the current snapshot available while the next read refreshes it.
    revalidateTag('products', 'max');
  }

  return (
    <main className="catalog-shell">
      <header className="topbar">
        <div className="brand-mark" aria-hidden="true">AC</div>
        <div className="brand-copy"><span className="eyebrow">Operations</span><strong>Acme Commerce</strong></div>
        <div className="topbar-spacer" />
        <span className="environment">Production</span><div className="avatar" aria-label="Admin account">AD</div>
      </header>
      <section className="content">
        <div className="breadcrumb">Catalog <span>/</span> Products</div>
        <div className="page-heading">
          <div><p className="eyebrow">Product catalog</p><h1>Products</h1><p className="subheading">Manage pricing, inventory, and availability across your storefront.</p></div>
          <form action={syncCatalog}><button className="sync-button" type="submit"><span aria-hidden="true">↻</span>Sync latest catalog</button></form>
        </div>
        <div className="toolbar">
          <div className="search-control" role="search"><span aria-hidden="true">⌕</span><input aria-label="Search products" placeholder="Search products" /></div>
          <button className="filter-button" type="button">Filter <span aria-hidden="true">⌄</span></button><span className="result-count">{products.length} products</span>
        </div>
        <div className="table-wrap"><table><thead><tr><th>Product</th><th>Price</th><th>Inventory</th><th>Status</th><th><span className="sr-only">Actions</span></th></tr></thead><tbody>
          {products.map(product => <tr key={product.id}><td><div className="product-cell"><span className="product-icon">{product.name.slice(0, 1)}</span><strong>{product.name}</strong></div></td><td>${product.price.toLocaleString('en-US', { minimumFractionDigits: 2 })}</td><td className={product.inventory === 0 ? 'low-stock' : ''}>{product.inventory} units</td><td><span className={`status ${product.status === 'Active' ? 'status-active' : 'status-out'}`}><span />{product.status}</span></td><td><button className="more-button" type="button" aria-label={`More actions for ${product.name}`}>•••</button></td></tr>)}
        </tbody></table></div>
      </section>
    </main>
  );
}

