import { unstable_cache } from 'next/cache';

const PRODUCTS_TAG = 'products';

async function queryAllProducts() {
  await new Promise(resolve => setTimeout(resolve, 100));

  return [
    { id: 1, name: 'Laptop', price: 999, inventory: 42, status: 'Active' },
    { id: 2, name: 'Phone', price: 699, inventory: 18, status: 'Active' },
    { id: 3, name: 'Tablet', price: 499, inventory: 0, status: 'Out of stock' },
    { id: 4, name: 'Headphones', price: 199, inventory: 76, status: 'Active' },
    { id: 5, name: 'Watch', price: 299, inventory: 11, status: 'Active' }
  ];
}

const getCachedProducts = unstable_cache(queryAllProducts, ['products'], {
  tags: [PRODUCTS_TAG],
  revalidate: 60
});

export async function getAllProducts() {
  return getCachedProducts();
}

